    # Parse each series and determine the global minimum and median timestamp across all entries
    global_min_timestamp = None
    global_median_timestamp = None
    for series in series_list:
        timestamps = series["timestamps"]
        if not timestamps:
            continue
        if global_min_timestamp is None or timestamps[0] < global_min_timestamp:
            global_min_timestamp = timestamps[0]
        if global_median_timestamp is None or timestamps[len(timestamps) // 2] < global_median_timestamp:
