    # Select entries in the lower half [global_min, median]
    selected_series = []
    for series in series_list:
        timestamps = series["timestamps"]
        if not timestamps:
            continue
        if global_min_timestamp <= timestamps[0] <= global_median_timestamp:
            selected_series.append(series)

    # Merge the selected sub-series
    merged_series = {}
    for series in selected_series:
        for key, value in series.items():
            if key not in merged_series:
                merged_series[key] = value
            else:
                merged_series[key] += value

    # Return the merged count
    return len(merged_series["timestamps"])

